 tkinter as tkfrom tkinter import messagebox, simpledialogimport jsonimport reimport osSTUDENT_FILE = &#x27;students.json&#x27;def load_students(): if not os.path.exists(STUDENT_FILE): return [] with open(STUDENT_FILE, &#x27;r&#x27;, encoding=&#x27;utf-8&#x27;) as file: return json.load(file)def save_students(students): with open(STUDENT_FILE, &#x27;w&#x27;, encoding=&#x27;utf-8&#x27;) as file: json.dump(students, file, ensure_ascii=False, indent=2)def show_students(students): sorted_students = sorted(students, key=lambda x: x[&#x27;id&#x27;]) # 按学号排序 students_text = &quot;&quot; for student in sorted_students: students_text += f&quot;学号: &#123;student[&#x27;id&#x27;]&#125;
