&quot; return students_textdef validate_id(student_id): return bool(student_id.strip())def add_student(students): dialog = tk.Toplevel() dialog.title(&quot;添加学生信息&quot;) dialog.geometry(&quot;250x200+900+400&quot;) tk.Label(dialog, text=&quot;学号：&quot;).grid(row=0, column=0, padx=10, pady=5) id_var = tk.StringVar() tk.Entry(dialog, textvariable=id_var).grid(row=0, column=1, padx=10, pady=5) tk.Label(dialog, text=&quot;姓名：&quot;).grid(row=1, column=0, padx=10, pady=5) name_var = tk.StringVar() tk.Entry(dialog, textvariable=name_var).grid(row=1, column=1, padx=10, pady=5) tk.Label(dialog, text=&quot;年龄：&quot;).grid(row=2, column=0, padx=10, pady=5) age_var = tk.StringVar() tk.Entry(dialog, textvariable=age_var).grid(row=2, column=1, padx=10, pady=5) tk.Label(dialog, text=&quot;性别：&quot;).grid(row=3, column=0, padx=10, pady=5) gender_var = tk.StringVar() gender_var.set(&quot;男&quot;) gender_menu = tk.OptionMenu(dialog, gender_var, &quot;男&quot;, &quot;女&quot;) gender_menu.grid(row=3, column=1, padx=10, pady=5) def add_student_action(): student_info = &#123; &#x27;id&#x27;: id_var.get(), &#x27;name&#x27;: name_var.get(), &#x27;age&#x27;: age_var.get(), &#x27;gender&#x27;: gender_var.get() &#125; if not student_info[&#x27;id&#x27;] or not validate_id(student_info[&#x27;id&#x27;]): messagebox.showerror(&quot;错误&quot;, &quot;学号格式错误，请重新输入。&quot;) return if any(student[&#x27;id&#x27;] == student_info[&#x27;id&#x27;] for student in students): messagebox.showerror(&quot;错误&quot;, &quot;学号已存在，请重新输入。&quot;) return students.append(student_info) messagebox.showinfo(&quot;成功&quot;, &quot;学生信息添加成功！&quot;) dialog.destroy() add_button = tk.Button(dialog, text=&quot;添加&quot;, command=add_student_action) add_button.grid(row=4, columnspan=2, pady=10)def edit_student(students): student_id = simpledialog.askstring(&quot;输入&quot;, &quot;请输入要编辑的学号：&quot;) if not student_id or not validate_id(student_id): messagebox.showerror(&quot;错误&quot;, &quot;学号格式错误，请重新输入。&quot;) return student = next((s for s in students if s[&#x27;id&#x27;] == student_id), None) if student: messagebox.showinfo(&quot;信息&quot;, f&quot;学号: &#123;student[&#x27;id&#x27;]&#125;
