性别: &#123;student[&#x27;gender&#x27;]&#125;&quot;) dialog = tk.Toplevel() dialog.title(&quot;编辑学生信息&quot;) dialog.geometry(&quot;250x200+900+400&quot;) tk.Label(dialog, text=&quot;姓名：&quot;).grid(row=1, column=0, padx=10, pady=5) name_var = tk.StringVar(value=student[&#x27;name&#x27;]) tk.Entry(dialog, textvariable=name_var).grid(row=1, column=1, padx=10, pady=5) tk.Label(dialog, text=&quot;年龄：&quot;).grid(row=2, column=0, padx=10, pady=5) age_var = tk.StringVar(value=str(student[&#x27;age&#x27;])) tk.Entry(dialog, textvariable=age_var).grid(row=2, column=1, padx=10, pady=5) tk.Label(dialog, text=&quot;性别：&quot;).grid(row=3, column=0, padx=10, pady=5) gender_var = tk.StringVar(value=student[&#x27;gender&#x27;]) gender_menu = tk.OptionMenu(dialog, gender_var, &quot;男&quot;, &quot;女&quot;) gender_menu.grid(row=3, column=1, padx=10, pady=5) def edit_student_action(): student[&#x27;name&#x27;] = name_var.get() student[&#x27;age&#x27;] = int(age_var.get()) student[&#x27;gender&#x27;] = gender_var.get() messagebox.showinfo(&quot;成功&quot;, &quot;学生信息编辑成功！&quot;) dialog.destroy() edit_button = tk.Button(dialog, text=&quot;编辑&quot;, command=edit_student_action) edit_button.grid(row=4, columnspan=2, pady=10) else: messagebox.showerror(&quot;错误&quot;, &quot;未找到该学生信息。&quot;)def delete_student(students): student_id = simpledialog.askstring(&quot;输入&quot;, &quot;请输入要删除的学号：&quot;) if not student_id or not validate_id(student_id): messagebox.showerror(&quot;错误&quot;, &quot;学号格式错误，请重新输入。&quot;) return student = next((s for s in students if s[&#x27;id&#x27;] == student_id), None) if student: students.remove(student) messagebox.showinfo(&quot;成功&quot;, &quot;学生信息删除成功！&quot;) else: messagebox.showerror(&quot;错误&quot;, &quot;未找到该学生信息。&quot;)def main(): root = tk.Tk() root.title(&quot;学生信息管理系统&quot;) students = load_students() window_width = 800 window_height = 500 screen_width = root.winfo_screenwidth() screen_height = root.winfo_screenheight() x_position = (screen_width - window_width) // 2 y_position = (screen_height - window_height) // 2 root.geometry(f&quot;&#123;window_width&#125;x&#123;window_height&#125;+&#123;x_position&#125;+&#123;y_position&#125;&quot;) def show_students_command(): students_text = show_students(students) messagebox.showinfo(&quot;学生信息&quot;, students_text) def add_student_command(): add_student(students) def delete_student_command(): delete_student(students) def edit_student_command(): edit_student(students) def save_and_exit(): save_students(students) root.destroy() show_students_button = tk.Button(root, text=&quot;显示所有学生信息&quot;, command=show_students_command) show_students_button.pack() add_student_button = tk.Button(root, text=&quot;添加学生信息&quot;, command=add_student_command) add_student_button.pack() delete_student_button = tk.Button(root, text=&quot;删除学生信息&quot;, command=delete_student_command) delete_student_button.pack() edit_student_button = tk.Button(root, text=&quot;编辑学生信息&quot;, command=edit_student_command) edit_student_button.pack() exit_button = tk.Button(root, text=&quot;保存并退出&quot;, command=save_and_exit) exit_button.pack() root.mainloop()if __name__ == &quot;__main__&quot;: main()

